import{c as a,Q as t,j as r,m as i}from"./chunks/framework.BPKcPtvA.js";const g=JSON.parse('{"title":"How do I trigger a discrepancy audit?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/recipes/admin/run-discrepancy-audit.md","filePath":"guide/recipes/admin/run-discrepancy-audit.md","lastUpdated":1779094756000}'),s={name:"guide/recipes/admin/run-discrepancy-audit.md"};function o(n,e,c,d,l,p){return t(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="how-do-i-trigger-a-discrepancy-audit" tabindex="-1">How do I trigger a discrepancy audit? <a class="header-anchor" href="#how-do-i-trigger-a-discrepancy-audit" aria-label="Permalink to &quot;How do I trigger a discrepancy audit?&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Who can do this</p><p><strong>Platform Admin</strong> or <strong>Infra Ops</strong></p></div><p>The discrepancy audit compares MongoDB and Postgres state for each tenant and surfaces dangling rows (ghosts and orphans). A scheduled worker runs it automatically; you can also trigger an ad-hoc scan.</p><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><ol><li>Open <strong>System → Discrepancies</strong> in the sidebar.</li><li>Click <strong>Trigger Scan</strong> in the toolbar.</li><li>(Optional) Limit the scope to a specific <strong>instance</strong> or <strong>kind</strong> (<code>ghost</code>, <code>orphan</code>).</li><li>Confirm.</li></ol><h2 id="result" tabindex="-1">Result <a class="header-anchor" href="#result" aria-label="Permalink to &quot;Result&quot;">​</a></h2><p>The scan runs as a job — track it in <strong>Migrations</strong> (it&#39;s a system job type) or watch the Discrepancies inbox refresh. When the scan completes:</p><ul><li>Newly-detected discrepancies appear with status <strong>Open</strong>.</li><li>Previously open discrepancies still detected get their <code>last_seen_at</code> bumped.</li><li>Open discrepancies no longer detected auto-resolve with note <strong>no longer detected</strong>.</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./triage-discrepancy">How do I triage a discrepancy?</a></li></ul>',10)])])}const h=a(s,[["render",o]]);export{g as __pageData,h as default};
